INSERT INTO `#__jem_events` (`id`, `locid`, `dates`, `enddates`, `times`, `endtimes`, `title`, `alias`, `created_by`, `modified`, `modified_by`, `publish_up`, `publish_down`, `version`, `author_ip`, `created`, `introtext`, `fulltext`, `meta_keywords`, `meta_description`, `recurrence_first_id`, `recurrence_number`, `recurrence_type`, `recurrence_counter`, `recurrence_limit`, `recurrence_limit_date`, `recurrence_byday`, `recurrence_bylastday`, `datimage`, `checked_out`, `checked_out_time`, `registra`, `registra_from`, `registra_until`, `unregistra`, `unregistra_until`, `reginvitedonly`, `maxplaces`, `minbookeduser`, `maxbookeduser`, `reservedplaces`, `waitinglist`, `requestanswer`, `seriesbooking`, `singlebooking`, `hits`, `published`, `contactid`, `custom1`, `custom2`, `custom3`, `custom4`, `custom5`, `custom6`, `custom7`, `custom8`, `custom9`, `custom10`, `created_by_alias`, `access`, `metadata`, `featured`, `attribs`, `language`, `event_status`, `ticket_availability`, `type_id`) VALUES
(12, 4, DATE_SUB(LAST_DAY(CURDATE() + INTERVAL 1 MONTH), INTERVAL ((DAYOFWEEK(LAST_DAY(CURDATE() + INTERVAL 1 MONTH)) + 1) % 7) DAY), NULL, '18:30:00', '20:00:00', 'Museum Technology Talk at the Prado', 'museum-technology-talk-prado', 62, NULL, 0, NOW() - INTERVAL 1 DAY, NULL, 1, '127.0.0.1', NOW() - INTERVAL 1 DAY, 'A free evening talk at the Museo del Prado about digital tools, visitor services, and how event management extensions such as JEM can support museum programmes.', 'The session is designed as a demo-friendly museum event: limited room capacity, two seats per user, waiting list enabled, a downloadable handout, and supporting links. It shows how JEM can manage cultural events where registration, attachments, links, venue data, and recurrence work together.', 'museum, prado, madrid, technology, jem', 'Free museum technology talk at the Museo del Prado with limited registration.', 0, 6, 4, 0, 0, DATE_SUB(LAST_DAY(CURDATE() + INTERVAL 3 MONTH), INTERVAL ((DAYOFWEEK(LAST_DAY(CURDATE() + INTERVAL 3 MONTH)) + 1) % 7) DAY), 'FR', '', 'event-prado-museum-technology-talk.webp', NULL, NULL, 1, NOW(), TIMESTAMP(DATE_SUB(LAST_DAY(CURDATE() + INTERVAL 1 MONTH), INTERVAL ((DAYOFWEEK(LAST_DAY(CURDATE() + INTERVAL 1 MONTH)) + 1) % 7) DAY), '17:30:00'), 1, TIMESTAMP(DATE_SUB(LAST_DAY(CURDATE() + INTERVAL 1 MONTH), INTERVAL ((DAYOFWEEK(LAST_DAY(CURDATE() + INTERVAL 1 MONTH)) + 1) % 7) DAY), '12:00:00'), 0, 25, 1, 2, 0, 1, 0, 1, 0, 0, 1, '', '', '', '', '', '', '', '', '', '', '', '', 1, '', 1, '{"attachments_layout":"column","links_layout":"row","links_order":"image_icon_text"}', '*', 'scheduled', 'instock', (SELECT `id` FROM `#__jem_types` WHERE `alias` = 'exhibition' AND `entity` = 1 ORDER BY `id` DESC LIMIT 1)),
(13, 5, CURDATE() + INTERVAL 21 DAY, NULL, '18:30:00', '20:30:00', 'Louvre Small Group Tour', 'louvre-small-group-tour', 62, NULL, 0, NOW() - INTERVAL 1 DAY, NULL, 1, '127.0.0.1', NOW() - INTERVAL 1 DAY, 'A small-group guided tour at the Louvre focused on major works and visitor routes.', 'This museum tour demonstrates capacity management with 12 available places, a maximum of two places per user, and a waiting list once the tour is full.', 'museum, louvre, paris, guided tour', 'Limited-capacity guided tour at the Louvre in Paris.', 0, 0, 0, 0, 0, NULL, '', '', 'event-louvre-small-group-tour.webp', NULL, NULL, 1, TIMESTAMP(DATE_ADD(CURDATE(), INTERVAL 2 DAY), '09:00:00'), TIMESTAMP(DATE_ADD(CURDATE(), INTERVAL 21 DAY), '17:30:00'), 1, TIMESTAMP(DATE_ADD(CURDATE(), INTERVAL 21 DAY), '12:00:00'), 0, 12, 1, 2, 0, 1, 0, 0, 0, 0, 1, '', '', '', '', '', '', '', '', '', '', '', '', 1, '', 0, '', '*', 'scheduled', 'preorder', (SELECT `id` FROM `#__jem_types` WHERE `alias` = 'guided-tour' AND `entity` = 1 ORDER BY `id` DESC LIMIT 1)),
(14, 6, CURDATE() + INTERVAL 32 DAY, NULL, '17:00:00', '19:00:00', 'Science Museum Discovery Tour', 'science-museum-discovery-tour', 62, NULL, 0, NOW() - INTERVAL 1 DAY, NULL, 1, '127.0.0.1', NOW() - INTERVAL 1 DAY, 'A compact after-hours discovery tour at the Science Museum in London.', 'This sample tour keeps the group deliberately small with only five places, a maximum of two places per user, and waiting list support so the registration workflow is visible in the demo.', 'museum, science, london, guided tour', 'Limited-capacity discovery tour at the Science Museum.', 0, 0, 0, 0, 0, NULL, '', '', 'event-science-museum-discovery-tour.webp', NULL, NULL, 1, NULL, TIMESTAMP(DATE_ADD(CURDATE(), INTERVAL 32 DAY), '16:00:00'), 1, TIMESTAMP(DATE_ADD(CURDATE(), INTERVAL 32 DAY), '12:00:00'), 0, 5, 1, 2, 0, 1, 0, 0, 0, 0, 1, '', '', '', '', '', '', '', '', '', '', '', '', 1, '', 0, '', '*', 'scheduled', 'instock', (SELECT `id` FROM `#__jem_types` WHERE `alias` = 'guided-tour' AND `entity` = 1 ORDER BY `id` DESC LIMIT 1)),
(15, 4, DATE_SUB(LAST_DAY(CURDATE() + INTERVAL 2 MONTH), INTERVAL ((DAYOFWEEK(LAST_DAY(CURDATE() + INTERVAL 2 MONTH)) + 1) % 7) DAY), NULL, '18:30:00', '20:00:00', 'Museum Technology Talk at the Prado', 'museum-technology-talk-prado-2', 62, NULL, 0, NOW() - INTERVAL 1 DAY, NULL, 1, '127.0.0.1', NOW() - INTERVAL 1 DAY, 'Second monthly session of the free Prado museum technology talk series.', 'This recurring instance keeps the same registration rules as the first session: 25 places, a maximum of two places per user, and waiting list support.', 'museum, prado, madrid, technology, jem', 'Second recurring museum technology talk at the Museo del Prado.', 12, 6, 4, 1, 0, DATE_SUB(LAST_DAY(CURDATE() + INTERVAL 3 MONTH), INTERVAL ((DAYOFWEEK(LAST_DAY(CURDATE() + INTERVAL 3 MONTH)) + 1) % 7) DAY), 'FR', '', 'event-prado-museum-technology-talk.webp', NULL, NULL, 1, NOW(), TIMESTAMP(DATE_SUB(LAST_DAY(CURDATE() + INTERVAL 2 MONTH), INTERVAL ((DAYOFWEEK(LAST_DAY(CURDATE() + INTERVAL 2 MONTH)) + 1) % 7) DAY), '17:30:00'), 1, TIMESTAMP(DATE_SUB(LAST_DAY(CURDATE() + INTERVAL 2 MONTH), INTERVAL ((DAYOFWEEK(LAST_DAY(CURDATE() + INTERVAL 2 MONTH)) + 1) % 7) DAY), '12:00:00'), 0, 25, 1, 2, 0, 1, 0, 1, 0, 0, 1, '', '', '', '', '', '', '', '', '', '', '', '', 1, '', 0, '{"attachments_layout":"column","links_layout":"row","links_order":"image_icon_text"}', '*', 'scheduled', 'instock', (SELECT `id` FROM `#__jem_types` WHERE `alias` = 'exhibition' AND `entity` = 1 ORDER BY `id` DESC LIMIT 1)),
(16, 4, DATE_SUB(LAST_DAY(CURDATE() + INTERVAL 3 MONTH), INTERVAL ((DAYOFWEEK(LAST_DAY(CURDATE() + INTERVAL 3 MONTH)) + 1) % 7) DAY), NULL, '18:30:00', '20:00:00', 'Museum Technology Talk at the Prado', 'museum-technology-talk-prado-3', 62, NULL, 0, NOW() - INTERVAL 1 DAY, NULL, 1, '127.0.0.1', NOW() - INTERVAL 1 DAY, 'Third monthly session of the free Prado museum technology talk series.', 'This recurring instance completes the three-month sample series and keeps the same registration and waiting list settings.', 'museum, prado, madrid, technology, jem', 'Third recurring museum technology talk at the Museo del Prado.', 12, 6, 4, 2, 0, DATE_SUB(LAST_DAY(CURDATE() + INTERVAL 3 MONTH), INTERVAL ((DAYOFWEEK(LAST_DAY(CURDATE() + INTERVAL 3 MONTH)) + 1) % 7) DAY), 'FR', '', 'event-prado-museum-technology-talk.webp', NULL, NULL, 1, NOW(), TIMESTAMP(DATE_SUB(LAST_DAY(CURDATE() + INTERVAL 3 MONTH), INTERVAL ((DAYOFWEEK(LAST_DAY(CURDATE() + INTERVAL 3 MONTH)) + 1) % 7) DAY), '17:30:00'), 1, TIMESTAMP(DATE_SUB(LAST_DAY(CURDATE() + INTERVAL 3 MONTH), INTERVAL ((DAYOFWEEK(LAST_DAY(CURDATE() + INTERVAL 3 MONTH)) + 1) % 7) DAY), '12:00:00'), 0, 25, 1, 2, 0, 1, 0, 1, 0, 0, 1, '', '', '', '', '', '', '', '', '', '', '', '', 1, '', 0, '{"attachments_layout":"column","links_layout":"row","links_order":"image_icon_text"}', '*', 'scheduled', 'instock', (SELECT `id` FROM `#__jem_types` WHERE `alias` = 'exhibition' AND `entity` = 1 ORDER BY `id` DESC LIMIT 1)),
(17, 5, CURDATE(), NULL, '09:30:00', '11:00:00', 'Louvre Masters Preview', 'louvre-masters-preview-today', 62, NULL, 0, NOW() - INTERVAL 1 DAY, NULL, 1, '127.0.0.1', NOW() - INTERVAL 1 DAY, 'A morning museum preview built for the Day timeline demo, with a clear start time, visual image, and compact cultural programme.', 'Visitors get a guided preview of selected masterworks, designed to show how JEM presents short museum sessions with registration, venue and category styling in a timeline layout.', 'museum, louvre, exhibition, timeline', 'Morning museum preview for the Day timeline sample.', 0, 0, 0, 0, 0, NULL, '', '', 'event-louvre-masters-preview.webp', NULL, NULL, 1, TIMESTAMP(CURDATE(), '08:00:00'), TIMESTAMP(CURDATE(), '09:00:00'), 1, TIMESTAMP(CURDATE(), '08:30:00'), 0, 18, 1, 2, 0, 1, 0, 0, 0, 0, 1, '', '', '', '', '', '', '', '', '', '', '', '', 1, '', 1, '{"links_layout":"row","links_order":"image_icon_text","attachments_layout":"column"}', '*', 'scheduled', 'instock', (SELECT `id` FROM `#__jem_types` WHERE `alias` = 'exhibition' AND `entity` = 1 ORDER BY `id` DESC LIMIT 1)),
(18, 1, CURDATE(), NULL, '19:00:00', '22:00:00', 'House Dance Social', 'house-dance-social-today', 62, NULL, 0, NOW() - INTERVAL 1 DAY, NULL, 1, '127.0.0.1', NOW() - INTERVAL 1 DAY, 'An evening house dance social for the Day timeline demo, adding a warmer music and movement slot after the museum events.', 'Open floor, short intro session and social dancing. This sample is useful for checking category colour, event type icon, registration limits and evening timeline spacing.', 'house, dancing, social, timeline', 'Evening house dance social for the Day timeline sample.', 0, 0, 0, 0, 0, NULL, '', '', 'event-electronic-beats.webp', NULL, NULL, 1, TIMESTAMP(CURDATE(), '12:00:00'), TIMESTAMP(CURDATE(), '18:30:00'), 1, TIMESTAMP(CURDATE(), '16:00:00'), 0, 40, 1, 4, 0, 1, 0, 0, 0, 0, 1, '', '', '', '', '', '', '', '', '', '', '', '', 1, '', 1, '{"links_layout":"column","links_order":"icon_text_image","attachments_layout":"row"}', '*', 'scheduled', 'instock', (SELECT `id` FROM `#__jem_types` WHERE `alias` = 'dancing' AND `entity` = 1 ORDER BY `id` DESC LIMIT 1));
